import React, { useState, useCallback } from 'react';
import { InputBox } from '@semparar/design-system-app';
import type { SDUIComponentProps, SDUIContext, SDUIValidation } from '../models';
import { validateField } from '../utils/validation';

interface PointsInputProps extends SDUIComponentProps {
  label: string;
  placeholder?: string;
  keyboardType?: string;
  textRight?: string;
  textError?: string;
  mb?: string;
  contextKey?: string;
  validation?: SDUIValidation;
}

function buildValidationContext(
  context: SDUIContext,
  contextKey: string | undefined,
  value: string,
): SDUIContext {
  if (!contextKey) return context;

  const segments = contextKey.split('.');
  if (segments.length === 1) {
    return { ...context, [segments[0]]: parseFloat(value) || 0 };
  }

  const [root, ...rest] = segments;
  const parent = (context[root] ?? {}) as SDUIContext;
  let nested: SDUIContext = { ...parent };
  let ref = nested;
  for (let i = 0; i < rest.length - 1; i++) {
    const child = { ...((ref[rest[i]] ?? {}) as SDUIContext) };
    ref[rest[i]] = child;
    ref = child;
  }
  ref[rest[rest.length - 1]] = parseFloat(value) || 0;

  return { ...context, [root]: nested };
}

export default function PointsInputAdapter({
  props,
  context,
}: {
  props: PointsInputProps;
  context: SDUIContext;
}) {
  const {
    label,
    placeholder = '0',
    keyboardType = 'number-pad',
    textRight,
    textError,
    mb,
    contextKey,
    validation,
  } = props;

  const [value, setValue] = useState('');
  const [validationError, setValidationError] = useState<string | null>(null);

  const handleChange = useCallback(
    (text: string) => {
      setValue(text);
      if (!validation) return;
      const ctx = buildValidationContext(context, contextKey, text);
      setValidationError(text.length > 0 ? validateField(validation, ctx) : null);
    },
    [validation, context, contextKey],
  );

  const handleUseAll = useCallback(() => {
    // In a real implementation, this would read from context/store
  }, []);

  const displayError = validationError ?? (textError ? String(textError) : undefined);

  return (
    <InputBox
      label={String(label)}
      placeholder={String(placeholder)}
      showLabel
      keyboardType={keyboardType}
      value={value}
      onChangeText={handleChange}
      error={!!validationError}
      textError={displayError}
      textRight={textRight ? String(textRight) : undefined}
      onPressTextRight={textRight ? handleUseAll : undefined}
      mb={mb}
    />
  );
}

